const ciudad = {
  nombre: 'Cali',
  pais: 'Colombia',
  poblacion: 2200000
};

console.log(ciudad.nombre);     // 'Cali'
console.log(ciudad.poblacion);  // 2200000

// Modificar una propiedad existente
ciudad.poblacion = 2300000;
console.log(ciudad.poblacion);  // 2300000

const libro = { titulo: 'Cien años de soledad', autor: 'García Márquez' };

// Acceso dinámico con variable
const propiedad = 'autor';
console.log(libro[propiedad]); // 'García Márquez'

// Agregar propiedad nueva
libro['paginas'] = 471;
console.log(libro.paginas); // 471

const temperatura = {
  celsius: 25,
  aFahrenheit: function() {
    return this.celsius * 9/5 + 32;
  }
};

console.log(temperatura.celsius);      // 25
console.log(temperatura.aFahrenheit()); // 77
